mapper.select:
select
FROM normal_work_order t3 INNER JOIN ( SELECT DISTINCT t2.order_no as task_order_no FROM normal_work_order_task t2 WHERE
t2.current_node_code IN ( SELECT t1.node_code FROM role_status_mapping t1 WHERE t1.display_status = #{model.displayStatus} AND t1.role_code = '1' ) and t2.valid = '1' and t2.level = '0'
AND FIND_IN_SET(#{model.coOrccId}, t2.co_unit_ids)
AND FIND_IN_SET(#{model.coOrccId}, t2.cc_unit_ids)
t2.current_node_code IN ( SELECT t1.node_code FROM role_status_mapping t1 WHERE t1.display_status = #{model.displayStatus} AND t1.role_code = #{model.roleCode} ) AND t2.lead_unit_id = #{model.leadUnitId} and t2.valid = '1' and t2.level = '0'
) t4 ON t3.order_no = t4.task_order_no
${ew.sqlSegment}
AND TIMESTAMPDIFF(HOUR, NOW(), t3.region_deadline) <= #{model.expireHour}

SELECT t1.`name`, IFNULL(sign_stat.signCount, 0) AS signCount, IFNULL(finish_stat.finishCount, 0) AS finishCount, -- 重新计算签收排名 (基于合并后的完整数据) DENSE_RANK() OVER (ORDER BY IFNULL(sign_stat.signCount, 0) DESC) AS signRanking, -- 重新计算办结排名 (基于合并后的完整数据) DENSE_RANK() OVER (ORDER BY IFNULL(finish_stat.finishCount, 0) DESC) AS finishRanking FROM `base_org` t1 -- 1. 关联签收统计子查询 LEFT JOIN ( SELECT t1.id, t1.name, COUNT(t2.id) AS signCount FROM `base_org` t1 LEFT JOIN work_order_dynamic t2 ON t1.id = t2.dept_id AND t2.process_type = '签收' -- 筛选条件放在 ON 中以保证 count 为 0 AND DATE_FORMAT(t2.created_time, '%Y-%m') = DATE_FORMAT(NOW(), '%Y-%m') WHERE t1.parent_id <> 0 GROUP BY t1.id, t1.name ) sign_stat ON t1.id = sign_stat.id
-- 2. 关联办结统计子查询 LEFT JOIN ( SELECT t1.id, t1.name, COUNT(t2.id) AS finishCount FROM `base_org` t1 LEFT JOIN normal_work_order_task t2 ON t1.id = t2.lead_unit_id AND t2.current_node_code = '13.1' AND t2.valid = '1' -- 筛选条件放在 ON 中 AND DATE_FORMAT(t2.created_time, '%Y-%m') = DATE_FORMAT(NOW(), '%Y-%m') WHERE t1.parent_id <> 0 GROUP BY t1.id, t1.name ) finish_stat ON t1.id = finish_stat.id
WHERE t1.parent_id <> 0 ORDER BY finishRanking;
